import{_ as d,M as a,p as n,q as h,R as i,t as l,N as e,a1 as r}from"./framework-5866ffd3.js";const o="/assets/Fetching_a_page-57b9cd0c.png",s={},_=r('<h1 id="http-状态消息" tabindex="-1"><a class="header-anchor" href="#http-状态消息" aria-hidden="true">#</a> HTTP 状态消息</h1><p><img src="'+o+'" alt=""></p><h2 id="html-错误消息" tabindex="-1"><a class="header-anchor" href="#html-错误消息" aria-hidden="true">#</a> HTML 错误消息</h2><p>当浏览器向 Web 服务器请求服务时，可能会发生错误，服务器可能会返回类似“404 Not Found”的错误代码。</p><p>通常将这些错误命名为 HTML 错误消息。但这些消息称为 HTTP 状态消息。 事实上，服务器总是为每个请求返回一条消息。 最常见的消息是 200 OK。</p><p>以下是可能返回的 HTTP 状态消息列表：</p><h2 id="rest-api" tabindex="-1"><a class="header-anchor" href="#rest-api" aria-hidden="true">#</a> Rest API</h2><ul><li>200 返回成功，GET、PUT 或 DELETE 请求成功。</li><li>204 无内容，POST 请求成功。</li><li>301 永久重定向。</li><li>302/307 临时重定向。</li><li>304 未修改，自上次请求以来。</li><li>331 用户名正确，需要密码。</li><li>332 需要登录帐户。</li><li>400 错误请求，缺少 API 请求的必需属性。</li><li>401 未授权，无效凭据进行身份验证将。</li><li>403 禁地，该请求不被允许。</li><li>404 未找到，无法访问资源</li><li>405 方法不允许，不支持该请求。</li><li>409 冲突，冲突资源已存在。</li><li>412 该请求被拒绝。</li><li>422 无法处理，无法处理该实体。</li><li>429 请求过多，用户超出了应用速率限制。</li><li>500 服务器错误，在处理请求时，服务器出现问题。</li><li>530 未登录。</li></ul><h2 id="http" tabindex="-1"><a class="header-anchor" href="#http" aria-hidden="true">#</a> HTTP</h2><h3 id="_1xx消息" tabindex="-1"><a class="header-anchor" href="#_1xx消息" aria-hidden="true">#</a> 1xx消息</h3><p><em>这一类型的状态码，代表请求已被接受，需要继续处理。这类响应是临时响应，只包含状态行和某些可选的响应头信息，并以空行结束。由于HTTP/1.0协议中没有定义任何1xx状态码，所以除非在某些试验条件下，服务器禁止向此类客户端发送1xx响应。 这些状态码代表的响应都是信息性的，标示客户应该采取的其他行动。</em></p><ul><li>100 - 客户端应当继续发送请求</li><li>101 - 切换协议</li><li>102 - 处理将被继续执行</li><li>103 Early Hints 与 Link 标头一起使用，允许浏览器在服务器准备响应时开始预加载资源</li></ul><h3 id="_2xx成功" tabindex="-1"><a class="header-anchor" href="#_2xx成功" aria-hidden="true">#</a> 2xx成功</h3><p><em>这一类型的状态码，代表请求已成功被服务器接收、理解、并接受。</em></p><ul><li>200 - （成功）请求已成功，请求所希望的响应头或数据体将随此响应返回。</li><li>201 - （已创建）请求成功且服务器已创建了新的资源。。</li><li>202 - （已接受）服务器已接受了请求，但尚未对其进行处理。</li><li>203 - （非授权信息）服务器已成功处理了请求，但返回了可能来自另一来源的信息。</li><li>204 - （无内容）服务器成功处理了请求，但未返回任何内容。</li><li>205 - （重置内容）服务器成功处理了请求，但未返回任何内容。</li><li>206 - （部分内容）服务器成功处理了部分 GET 请求。</li></ul><h3 id="_3xx重定向" tabindex="-1"><a class="header-anchor" href="#_3xx重定向" aria-hidden="true">#</a> 3xx重定向</h3><p><em>这类状态码代表需要客户端采取进一步的操作才能完成请求。通常，这些状态码用来重定向，后续的请求地址（重定向目标）在本次响应的Location域中指明。按照HTTP/1.0版规范的建议，浏览器不应自动访问超过5次的重定向。对重定向一般是由浏览器来控制重定向的次数，重定向会导致客户端不必要的资源消耗</em></p><ul><li>300 - 多重选择，被请求的资源有一系列可供选择的回馈信息。</li><li>301 - 永久移除，被请求的资源已永久移动到新位置。</li><li>302 - 临时移动，请求的资源现在临时从不同的URI响应请求。</li><li>303 - 查看其他位置，对应当前请求的响应可以在另一个URI上被找到，而且客户端应当采用GET的方式访问那个资源。</li><li>304 - 未修改。自从上次请求后，请求的网页未被修改过。服务器返回此响应时，不会返回网页内容。</li><li>305 - 使用代理，被请求的资源必须通过指定的代理才能被访问。</li><li><s>306</s> - 临时重定向，在最新版的规范中，306状态码已经不再被使用。</li><li>307 请求的页面已临时重定向到新的 URL</li><li>308 请求的页面已永久重定向到新的 URL</li></ul><h3 id="_4xx客户端错误" tabindex="-1"><a class="header-anchor" href="#_4xx客户端错误" aria-hidden="true">#</a> 4xx客户端错误</h3><p><em>这类的状态码代表了客户端看起来可能发生了错误，妨碍了服务器的处理。</em></p>',20),c=r("<li>400 - 错误的请求。</li><li>401 - 访问被拒绝。</li><li>402 - 付款要求。</li><li>403 - 禁止访问 <ul><li>403.1 - 执行访问被禁止。</li><li>403.2 - 读访问被禁止。</li><li>403.3 - 写访问被禁止。</li><li>403.4 - 要求 SSL。</li><li>403.5 - 要求 SSL 128。</li><li>403.6 - IP 地址被拒绝。</li><li>403.7 - 要求客户端证书。</li><li>403.8 - 站点访问被拒绝。</li><li>403.9 - 用户数过多。</li><li>403.10 - 配置无效。</li><li>403.11 - 密码更改。</li><li>403.12 - 拒绝访问映射表。</li><li>403.13 - 客户端证书被吊销。</li><li>403.14 - 拒绝目录列表。</li><li>403.15 - 超出客户端访问许可。</li><li>403.16 - 客户端证书不受信任或无效。</li><li>403.17 - 客户端证书已过期或尚未生效。</li><li>403.18 - 在当前的应用程序池中不能执行所请求的 URL。</li><li>403.19 - 不能为这个应用程序池中的客户端执行 CGI。</li><li>403.20 - Passport 登录失败。</li></ul></li><li>404 - 未找到。 <ul><li>404.0 -（无） – 没有找到文件或目录。</li><li>404.1 - 无法在所请求的端口上访问 Web 站点。</li><li>404.2 - Web 服务扩展锁定策略阻止本请求。</li><li>404.3 - MIME 映射策略阻止本请求。</li></ul></li><li>405 - 用来访问本页面的 HTTP 谓词不被允许（方法不被允许）</li><li>406 - 客户端浏览器不接受所请求页面的 MIME 类型。</li><li>407 - 要求进行代理身份验证。</li><li>408 - 请求超时。</li><li>409 - 由于和被请求的资源的当前状态之间存在冲突，请求无法完成。</li><li>410 - 被请求的资源在服务器上已经不再可用，而且没有任何已知的转发地址。</li><li>411 - 服务器拒绝在没有定义Content-Length头的情况下接受请求。</li><li>412 - 前提条件失败。</li><li>413 – 请求实体太大。</li><li>414 - 请求 URI 太长。</li><li>415 – 不支持的媒体类型。</li><li>416 – 所请求的范围无法满足。</li><li>417 – 执行失败。</li>",18),x={href:"http://www.baike.com/wiki/%E6%81%B6%E6%90%9ERFC",target:"_blank",rel:"noopener noreferrer"},p=i("li",null,"421 – 从当前客户端所在的IP地址到服务器的连接数超过了服务器许可的最大范围。",-1),u=i("li",null,"422 – 请求格式正确，但是由于含有语义错误，无法响应。",-1),T=i("li",null,"423 – 当前资源被锁定。",-1),f=i("li",null,"424 – 由于之前的某个请求发生的错误，导致当前请求失败。",-1),b=i("li",null,"425 – 无序的集合。",-1),m=i("li",null,"426 – 客户端应当切换到TLS/1.0。",-1),E=i("li",null,"451 – （由IETF在2015核准后新增加）该访问因法律的要求而被拒绝。",-1),P=r('<h3 id="_5xx服务器错误" tabindex="-1"><a class="header-anchor" href="#_5xx服务器错误" aria-hidden="true">#</a> 5xx服务器错误</h3><p><em>这类状态码代表了服务器在处理请求的过程中有错误或者异常状态发生，也有可能是服务器意识到以当前的软硬件资源无法完成对请求的处理。</em></p><ul><li>500 - 内部服务器错误。</li><li>501 - 尚未实施，页眉值指定了未实现的配置。</li><li>502 - 错误网关，Web 服务器用作网关或代理服务器时收到了无效响应。</li><li>503 - 服务不可用，这个错误代码为 IIS 6.0 所专用。</li><li>504 - 网关超时，服务器作为网关或代理，未及时从上游服务器接收请求。</li><li>505 - HTTP 版本不受支持，服务器不支持请求中所使用的 HTTP 协议版本。</li><li>506 - 服务器没有正确配置。</li><li>507 - 存储空间不足。服务器无法存储完成请求所必须的内容。这个状况被认为是临时的。</li><li>509 - 带宽超过限制。这不是一个官方的状态码，但是仍被广泛使用。</li><li>510 - 没有扩展，获取资源所需要的策略并没有被满足。</li><li>511 - 客户端需要进行身份验证才能获得网络访问权限</li></ul><h2 id="ftp" tabindex="-1"><a class="header-anchor" href="#ftp" aria-hidden="true">#</a> FTP</h2><h3 id="_1xx初步" tabindex="-1"><a class="header-anchor" href="#_1xx初步" aria-hidden="true">#</a> 1xx初步</h3><p><em>肯定的初步答复，这些状态代码指示一项操作已经成功开始，但客户端希望在继续操作新命令前得到另一个答复。</em></p><ul><li>110 重新启动标记答复。</li><li>120 服务已就绪，在 nnn 分钟后开始。</li><li>125 数据连接已打开，正在开始传输。</li><li>150 文件状态正常，准备打开数据连接。</li></ul><h3 id="_2xx完成" tabindex="-1"><a class="header-anchor" href="#_2xx完成" aria-hidden="true">#</a> 2xx完成</h3><p><em>肯定的完成答复，一项操作已经成功完成。客户端可以执行新命令。</em></p><ul><li>200 命令确定。</li><li>202 未执行命令，站点上的命令过多。</li><li>211 系统状态，或系统帮助答复。</li><li>212 目录状态。</li><li>213 文件状态。</li><li>214 帮助消息。</li><li>215 NAME 系统类型，其中，NAME 是 Assigned Numbers 文档中所列的正式系统名称。</li><li>220 服务就绪，可以执行新用户的请求。</li><li>221 服务关闭控制连接。如果适当，请注销。</li><li>225 数据连接打开，没有进行中的传输。</li><li>226 关闭数据连接。请求的文件操作已成功（例如，传输文件或放弃文件）。</li><li>227 进入被动模式 (h1,h2,h3,h4,p1,p2)。</li><li>230 用户已登录，继续进行。</li><li>250 请求的文件操作正确，已完成。</li><li>257 已创建“PATHNAME”。</li></ul><h3 id="_3xx中间" tabindex="-1"><a class="header-anchor" href="#_3xx中间" aria-hidden="true">#</a> 3xx中间</h3><p><em>肯定的中间答复，该命令已成功，但服务器需要更多来自客户端的信息以完成对请求的处理。</em></p><ul><li>331 用户名正确，需要密码。</li><li>332 需要登录帐户。</li><li>350 请求的文件操作正在等待进一步的信息。</li></ul><h3 id="_4xx瞬态否定" tabindex="-1"><a class="header-anchor" href="#_4xx瞬态否定" aria-hidden="true">#</a> 4xx瞬态否定</h3><p><em>瞬态否定的完成答复，该命令不成功，但错误是暂时的。如果客户端重试命令，可能会执行成功。</em></p><ul><li>421 服务不可用，正在关闭控制连接。如果服务确定它必须关闭，将向任何命令发送这一应答。</li><li>425 无法打开数据连接。</li><li>426 Connection closed; transfer aborted.</li><li>450 未执行请求的文件操作。文件不可用（例如，文件繁忙）。</li><li>451 请求的操作异常终止：正在处理本地错误。</li><li>452 未执行请求的操作。系统存储空间不够。</li></ul><h2 id="_5xx永久性否定" tabindex="-1"><a class="header-anchor" href="#_5xx永久性否定" aria-hidden="true">#</a> 5xx永久性否定</h2><p><em>永久性否定的完成答复，该命令不成功，错误是永久性的。如果客户端重试命令，将再次出现同样的错误。</em></p><ul><li>500 语法错误，命令无法识别。这可能包括诸如命令行太长之类的错误。</li><li>501 在参数中有语法错误。</li><li>502 未执行命令。</li><li>503 错误的命令序列。</li><li>504 未执行该参数的命令。</li><li>530 未登录。</li><li>532 存储文件需要帐户。</li><li>550 未执行请求的操作。文件不可用（例如，未找到文件，没有访问权限）。</li><li>551 请求的操作异常终止：未知的页面类型。</li><li>552 请求的文件操作异常终止：超出存储分配（对于当前目录或数据集）。</li><li>553 未执行请求的操作。不允许的文件名。</li></ul><h2 id="_6xx受保护" tabindex="-1"><a class="header-anchor" href="#_6xx受保护" aria-hidden="true">#</a> 6xx受保护</h2><ul><li>600 Series，Replies regarding confidentiality and integrity</li><li>631 Integrity protected reply.</li><li>632 Confidentiality and integrity protected reply.</li><li>633 Confidentiality protected reply.</li></ul><h2 id="websockets状态码" tabindex="-1"><a class="header-anchor" href="#websockets状态码" aria-hidden="true">#</a> WebSockets状态码</h2><p><em>WebSockets 的CloseEvent 会在连接关闭时发送给使用 WebSockets 的客户端。它在 WebSocket 对象的 onclose 事件监听器中使用。服务端发送的关闭码，以下为已分配的状态码。</em></p><table><thead><tr><th>状态码</th><th>名称</th><th>描述</th></tr></thead><tbody><tr><td>0–999</td><td>-</td><td>保留段, 未使用。</td></tr><tr><td>1000</td><td>CLOSE_NORMAL</td><td>正常关闭; 无论为何目的而创建, 该链接都已成功完成任务。</td></tr><tr><td>1001</td><td>CLOSE_GOING_AWAY</td><td>终端离开, 可能因为服务端错误, 也可能因为浏览器正从打开连接的页面跳转离开。</td></tr><tr><td>1002</td><td>CLOSE_PROTOCOL_ERROR</td><td>由于协议错误而中断连接。</td></tr><tr><td>1003</td><td>CLOSE_UNSUPPORTED</td><td>由于接收到不允许的数据类型而断开连接 (如仅接收文本数据的终端接收到了二进制数据)。</td></tr><tr><td>1004</td><td>-</td><td>保留。 其意义可能会在未来定义。</td></tr><tr><td>1005</td><td>CLOSE_NO_STATUS</td><td>保留。 表示没有收到预期的状态码。</td></tr><tr><td>1006</td><td>CLOSE_ABNORMAL</td><td>保留。 用于期望收到状态码时连接非正常关闭 (也就是说, 没有发送关闭帧)。</td></tr><tr><td>1007</td><td>Unsupported Data</td><td>由于收到了格式不符的数据而断开连接 (如文本消息中包含了非 UTF-8 数据)。</td></tr><tr><td>1008</td><td>Policy Violation</td><td>由于收到不符合约定的数据而断开连接。 这是一个通用状态码, 用于不适合使用 1003 和 1009 状态码的场景。</td></tr><tr><td>1009</td><td>CLOSE_TOO_LARGE</td><td>由于收到过大的数据帧而断开连接。</td></tr><tr><td>1010</td><td>Missing Extension</td><td>客户端期望服务器商定一个或多个拓展, 但服务器没有处理, 因此客户端断开连接。</td></tr><tr><td>1011</td><td>Internal Error</td><td>客户端由于遇到没有预料的情况阻止其完成请求, 因此服务端断开连接。</td></tr><tr><td>1012</td><td>Service Restart</td><td>服务器由于重启而断开连接。 [Ref]</td></tr><tr><td>1013</td><td>Try Again Later</td><td>服务器由于临时原因断开连接, 如服务器过载因此断开一部分客户端连接。 [Ref]</td></tr><tr><td>1014</td><td>-</td><td>由 WebSocket 标准保留以便未来使用。</td></tr><tr><td>1015</td><td>TLS Handshake</td><td>保留。 表示连接由于无法完成 TLS 握手而关闭 (例如无法验证服务器证书)。</td></tr><tr><td>1016–1999</td><td>-</td><td>由 WebSocket 标准保留以便未来使用。</td></tr><tr><td>2000–2999</td><td>-</td><td>由 WebSocket 拓展保留使用。</td></tr><tr><td>3000–3999</td><td>-</td><td>可以由库或框架使用。 不应由应用使用。 可以在 IANA 注册, 先到先得。</td></tr><tr><td>4000–4999</td><td>-</td><td>可以由应用使用。</td></tr></tbody></table><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料" aria-hidden="true">#</a> 参考资料</h2>',25),g={href:"https://en.wikipedia.org/wiki/List_of_HTTP_status_codes",target:"_blank",rel:"noopener noreferrer"},k={href:"https://en.wikipedia.org/wiki/List_of_FTP_server_return_codes",target:"_blank",rel:"noopener noreferrer"},L={href:"https://developer.mozilla.org/zh-CN/docs/Web/API/CloseEvent",target:"_blank",rel:"noopener noreferrer"},S={href:"https://en.wikipedia.org/wiki/HTTP_404#Custom_error_pages",target:"_blank",rel:"noopener noreferrer"},H={href:"https://en.wikipedia.org/wiki/List_of_FTP_server_return_codes",target:"_blank",rel:"noopener noreferrer"},I={href:"https://developer.mozilla.org/zh-CN/docs/Web/HTTP/Overview",target:"_blank",rel:"noopener noreferrer"},R={href:"http://www.getnetgoing.com/HTTP-403.html",target:"_blank",rel:"noopener noreferrer"},w={href:"https://www.vinaysahni.com/best-practices-for-a-pragmatic-restful-api",target:"_blank",rel:"noopener noreferrer"};function C(O,A){const t=a("ExternalLinkIcon");return n(),h("div",null,[_,i("ul",null,[c,i("li",null,[l("418 – 本操作码是在1998年作为IETF的传统"),i("a",x,[l("愚人节笑话"),e(t)]),l("。")]),p,u,T,f,b,m,E]),P,i("ul",null,[i("li",null,[i("a",g,[l("HTTP状态码列表"),e(t)])]),i("li",null,[i("a",k,[l("FTP状态码列表"),e(t)])]),i("li",null,[i("a",L,[l("MDN CloseEvent"),e(t)])]),i("li",null,[i("a",S,[l("HTTP 404"),e(t)])]),i("li",null,[i("a",H,[l("List of FTP server return codes"),e(t)])]),i("li",null,[i("a",I,[l("HTTP概述"),e(t)])]),i("li",null,[i("a",R,[l("Help for HTTP error 403: “Forbidden”"),e(t)])]),i("li",null,[i("a",w,[l("实用的 RESTful API 最佳实践"),e(t)])])])])}const v=d(s,[["render",C],["__file","httpmessages.html.vue"]]);export{v as default};
